// §2.2.7 — 线程安全 NAPI 桥接（TSFN）//// 背景：ArkJS 运行时（Panda EcmaVM）禁止多线程访问 NAPI。// `napi_call_function` 只能在创建 `napi_env` 的 UI 线程上调用。// 但 warp-main 线程（Rust 侧）需要调用 ArkTS 的回调函数。//// 方案：使用 N-API 标准 TSFN（Thread-Safe Function）机制。//   1. UI 线程上创建 TSFN（ohos_create_napi_bridge）//   2. 任意线程通过 TSFN 安全调用 NAPI（ohos_call_napi）//   3. TSFN 内部将请求排队到 UI 线程的消息队列，等待结果后返回//// 线程模型：//   UI 线程（ArkTS main thread）← TSFN 桥接 → warp-main 线程（Rust）#include <cstring>#include <condition_variable>#include <mutex>#include <napi/native_api.h>#include "napi_utils.h"#undef LOG_TAG#define LOG_TAG "NapiBridge"/// 一次 NAPI 调用的请求/响应结构。/// 由调用线程在栈上分配，TSFN 回调在同一栈上写入结果，信号量通知完成。struct NapiCallRequest {    char method[256];                   ///< 要调用的 NAPI 方法名    char arg[4096];                     ///< 参数字符串（可选，arg[0]='\0' 表示无参数）    char result[4096];                  ///< 结果缓冲区    std::mutex mtx;                     ///< 配合 cv 的互斥锁    std::condition_variable cv;         ///< 完成通知信号量    bool done = false;                  ///< 标记：TSFN 回调是否已完成};/// 全局 TSFN 句柄，在 Init() 时创建static napi_threadsafe_function g_tsfn = nullptr;/// TSFN 回调：在 UI 线程上执行真实的 NAPI 调用。/// context: 未使用/// data: NapiCallRequest*（由 ohos_call_napi_ex 传入）static void TSFNCallJS(napi_env env, napi_value js_cb, void* context, void* data) {    auto* req = static_cast<NapiCallRequest*>(data);    napi_value exports = nullptr;    napi_value fn = nullptr;    napi_value js_result = nullptr;    napi_value arg_val = nullptr;    napi_status call_status = napi_ok;    napi_status str_status = napi_ok;    size_t napi_str_len = 0;    bool has_arg = (req->arg[0] != '\0');    // 获取 exports    call_status = napi_get_reference_value(env, g_exports_ref, &exports);    if (call_status != napi_ok) {        req->result[0] = '\0';        goto done;    }    // 获取方法    call_status = napi_get_named_property(env, exports, req->method, &fn);    if (call_status != napi_ok) {        OH_LOG_WARN(LOG_APP, "TSFN: method '%{public}s' not found", req->method);        req->result[0] = '\0';        goto done;    }    // 有参数时创建 napi_value    if (has_arg) {        napi_create_string_utf8(env, req->arg, NAPI_AUTO_LENGTH, &arg_val);    }    // 调用 NAPI 方法    call_status = napi_call_function(        env, exports, fn,        has_arg ? 1 : 0,        has_arg ? &arg_val : nullptr,        &js_result    );    if (call_status != napi_ok) {        OH_LOG_WARN(LOG_APP, "TSFN: call '%{public}s' failed", req->method);        req->result[0] = '\0';        goto done;    }    // 将 NAPI 结果转为 C 字符串    str_status = napi_get_value_string_utf8(env, js_result, nullptr, 0, &napi_str_len);    if (str_status == napi_ok && napi_str_len > 0 && napi_str_len < sizeof(req->result)) {        napi_get_value_string_utf8(env, js_result, req->result, napi_str_len + 1, &napi_str_len);    } else {        req->result[0] = '\0';    }done:    std::lock_guard<std::mutex> lock(req->mtx);    req->done = true;    req->cv.notify_one();}// ── C FFI 桥 ─────────────────────────────────────────────────────────────────extern "C" {/// 创建全局 TSFN。必须在 UI 线程上调用（通常在 Init 或 ohos_init_service_bridge 中）。void ohos_create_napi_bridge(napi_env env) {    napi_value tsfn_name;    napi_create_string_utf8(env, "WarpNapiBridge", NAPI_AUTO_LENGTH, &tsfn_name);    napi_status status = napi_create_threadsafe_function(        env,        nullptr,           // func: 不包装 JS 函数，直接用回调        nullptr,           // async_resource: 不需要        tsfn_name,        0,                 // max_queue_size: 0 = 无限        1,                 // initial_thread_count        nullptr,           // finalize_data        nullptr,           // finalize_cb        nullptr,           // context        TSFNCallJS,        // call_js: UI 线程上执行的回调        &g_tsfn    );    if (status != napi_ok) {        OH_LOG_ERROR(LOG_APP, "ohos_create_napi_bridge: napi_create_threadsafe_function failed");        return;    }    // 不阻止进程退出    napi_unref_threadsafe_function(env, g_tsfn);    OH_LOG_INFO(LOG_APP, "ohos_create_napi_bridge: TSFN created");}/// 通过 TSFN 调用 NAPI 方法（无参数/有参数通用）。可在任意线程上调用。/// @param method NAPI 方法名/// @param arg 参数（可为 NULL 或无参数时 arg[0]=='\0'）/// @param result 输出缓冲区（可为 NULL 表示不关心返回值）/// @param max_len 输出缓冲区大小void ohos_call_napi_ex(const char* method, const char* arg, char* result, size_t max_len) {    NapiCallRequest req;    strncpy(req.method, method, sizeof(req.method) - 1);    req.method[sizeof(req.method) - 1] = '\0';    if (arg != nullptr && arg[0] != '\0') {        strncpy(req.arg, arg, sizeof(req.arg) - 1);    }    req.arg[sizeof(req.arg) - 1] = '\0';    req.done = false;    req.result[0] = '\0';    // 加入 UI 线程消息队列    napi_status status = napi_call_threadsafe_function(g_tsfn, &req, napi_tsfn_blocking);    if (status != napi_ok) {        OH_LOG_ERROR(LOG_APP, "ohos_call_napi_ex('%{public}s'): TSFN call failed", method);        if (result && max_len > 0) result[0] = '\0';        return;    }    // 等待 UI 线程处理完成    {        std::unique_lock<std::mutex> lock(req.mtx);        req.cv.wait(lock, [&req] { return req.done; });    }    if (result && max_len > 0) {        strncpy(result, req.result, max_len - 1);        result[max_len - 1] = '\0';    }}/// 兼容旧接口：无参数，字符串返回值。void ohos_call_napi(const char* method, char* result, size_t max_len) {    ohos_call_napi_ex(method, nullptr, result, max_len);}} // extern "C"